test.config:
indexer
{
	mem_limit = 16M
}

searchd
{

}

source test
{
	type = mysql


	sql_query = SELECT id, n, 'text' FROM test_table;
	sql_attr_uint = n

	sql_attr_multi = uint mva from query; select id, n mva from test_table
	sql_attr_multi = bigint mva from query; select id, n mva from test_table

}

index test
{
	source	= test
	path	= /test
}

source test_ms_base
{
	type = mysql


	sql_attr_uint = n
	sql_attr_multi = uint mva from query; select doc_id, tag from test_tags order by doc_id, tag
}

source test_ms_a : test_ms_base
{
	sql_query = SELECT id, n, text FROM test_docs WHERE src='a' ORDER BY id
}

source test_ms_b : test_ms_base
{
	sql_query = SELECT id, n, text FROM test_docs WHERE src='b' ORDER BY id
}

index test_ms
{
	source	= test_ms_a
	source	= test_ms_b
	path	= /test_ms
}

test.db_create:
CREATE TABLE test_table
(
	id INT NOT NULL,
	n INT UNSIGNED NOT NULL
);

CREATE TABLE test_tags
(
	doc_id INT NOT NULL,
	tag INT UNSIGNED NOT NULL
);

queries.sphinxql:
SELECT id, n, mva FROM test_ms ORDER BY id ASC;
SELECT id FROM test_ms WHERE any(mva)=100 ORDER BY id ASC;
SELECT id FROM test_ms WHERE any(mva)=201 ORDER BY id ASC;
SELECT id, n, mva FROM test_ms WHERE MATCH('alpha') ORDER BY id ASC;
SELECT id, n, mva FROM test_ms WHERE MATCH('beta') ORDER BY id ASC;
